(()=>{const root=document.querySelector("[data-countdown]");if(!root)return;const target=new Date(root.getAttribute("data-countdown")).getTime();if(Number.isNaN(target))return;const units=[["days",86400000],["hours",3600000],["minutes",60000],["seconds",1000],];const tick=()=>{let diff=Math.max(0,target-Date.now());units.forEach(([unit,ms])=>{const el=root.querySelector('[data-unit="'+unit+'"]');if(!el)return;const value=Math.floor(diff/ms);diff-=value*ms;el.textContent=String(value).padStart(2,"0");});};tick();setInterval(tick,1000);})();